import{_ as e,o as a,c as r,a4 as d}from"./chunks/framework.BhEBm8_q.js";const b=JSON.parse('{"title":"이어읽기와 독서중","description":"","frontmatter":{},"headers":[],"relativePath":"04-reading-progress.md","filePath":"04-reading-progress.md"}'),o={name:"04-reading-progress.md"};function i(l,t,n,s,h,c){return a(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="이어읽기와-독서중" tabindex="-1">이어읽기와 독서중 <a class="header-anchor" href="#이어읽기와-독서중" aria-label="Permalink to “이어읽기와 독서중”">​</a></h1><p><em>홈의 독서중 영역</em></p><p>문서를 열면 읽던 위치가 자동으로 저장되어, 다음에 열 때 그 위치부터 이어 읽습니다. 따로 저장 버튼을 누를 필요가 없습니다.</p><h2 id="자동-저장의-동작" tabindex="-1">자동 저장의 동작 <a class="header-anchor" href="#자동-저장의-동작" aria-label="Permalink to “자동 저장의 동작”">​</a></h2><ul><li>페이지를 넘기거나 스크롤하면 현재 위치가 갱신됩니다.</li><li>앱을 닫았다 다시 켜도 마지막 위치가 복원됩니다.</li><li>진행률은 표지와 리더에 함께 표시됩니다.</li></ul><h2 id="독서중-큐" tabindex="-1">독서중 큐 <a class="header-anchor" href="#독서중-큐" aria-label="Permalink to “독서중 큐”">​</a></h2><p>홈의 <code>독서중</code>은 실제 열람 활동을 기준으로 최근에 읽은 문서를 모아 둡니다. 바로 눌러 마지막 위치로 돌아갈 수 있어, &quot;어제 보던 그 문서&quot;를 찾아 헤맬 필요가 없습니다.</p><p>검색 결과로 잠깐 열어 본 문서까지 큐를 오염시키지 않도록, 가이드 문서나 일부 임시 열람은 독서중에 남기지 않습니다.</p><h2 id="ebook-책장-순서는-그대로" tabindex="-1">Ebook 책장 순서는 그대로 <a class="header-anchor" href="#ebook-책장-순서는-그대로" aria-label="Permalink to “Ebook 책장 순서는 그대로”">​</a></h2><p><code>Ebook 책장</code>은 문서를 추가한 순서를 유지합니다. 같은 문서를 다시 읽어도 책장 순서는 바뀌지 않으므로, 늘 같은 자리에서 문서를 찾을 수 있습니다. &quot;최근 읽은 순&quot;으로 보고 싶다면 <code>독서중</code>을 사용하면 됩니다.</p><h2 id="포맷별-위치-기준" tabindex="-1">포맷별 위치 기준 <a class="header-anchor" href="#포맷별-위치-기준" aria-label="Permalink to “포맷별 위치 기준”">​</a></h2><table tabindex="0"><thead><tr><th>포맷</th><th>위치 기준</th></tr></thead><tbody><tr><td>PDF</td><td>페이지 번호</td></tr><tr><td>TXT / Markdown</td><td>본문 위치(offset)</td></tr><tr><td>EPUB</td><td>챕터(spine)와 CFI</td></tr><tr><td>CBZ / CB7</td><td>이미지 순서</td></tr><tr><td>HWP / HWPX</td><td>페이지</td></tr></tbody></table><p>각 포맷은 자기 방식대로 위치를 기억하므로, 글자 크기나 화면을 바꿔도 읽던 지점을 최대한 맞춰 복원합니다.</p><blockquote><p>가이드 책장의 문서도 진행률과 북마크가 동작하지만, 독서중 큐에는 올라오지 않습니다.</p></blockquote>',14)])])}const _=e(o,[["render",i]]);export{b as __pageData,_ as default};
